import React, { memo, useState, useEffect, useRef, useCallback } from 'react';
import ReactDom from 'react-dom';
import styles from './popup.module.css';

const Popup = memo(({
  name,
  children,
  bridge,
  className = '',
  popupClassName = '',
  position = 'bottom',
  open,
  zIndex,
  style,
  render,
  round,
  closeOnMaskClick = false,
  noState, // 不监听url
  onClose,
  destroyOnClose,
  transparent,
}) => {
  const dataRef = useRef({
    first: true,
    render: !!render || false,
    locked: false, // 锁定监听事件，不予触发，处理多popup重叠使用
  });
  dataRef.current.noState = noState;
  // 是否已渲染
  const [initDom, setInitDom] = useState(!!render || false);
  const [inShow, setInShow] = useState(false);
  const [inStyle, setInStyle] = useState(undefined);

  const onMask = () => {
    if (onClose && closeOnMaskClick) {
      onClose(name);
    }
  };

  const enable_back = useCallback(() => {
    if (!dataRef.current.locked) {
      dataRef.current.bindEvent = false;
      window.removeEventListener('popstate', enable_back);
      onClose && onClose(name);
    }
  }, []);

  const toggleEvent = (state) => {
    // 弹框打开推入页面路由
    if (window.history && position === 'full') {
      if (state) {
        dataRef.current.bindEvent = true;
        window.history.pushState(null, null, document.URL)
        window.addEventListener('popstate', enable_back);
      } else if (dataRef.current.bindEvent) {
        window.removeEventListener('popstate', enable_back);
        window.history.go(-1);
      }
    }
  }

  const bridgeEvent = useRef({
    setLock: (st) => {
      dataRef.current.locked = st;
    }
  });

  useEffect(() => {
    dataRef.current.destroy = false;
    if (bridge) {
      bridge.current = bridgeEvent.current;
    }
    return () => {
      dataRef.current.bindEvent = false;
      window.removeEventListener('popstate', enable_back);
      dataRef.current.destroy = true;
    };
  }, []);

  useEffect(() => {
    if (style || zIndex) {
      const temp = { ...style};
      temp.zIndex = zIndex
      setInStyle(temp);
    } else {
      setInStyle(undefined);
    }
  }, [zIndex, style]);
  useEffect(() => {
    if (!dataRef.current.first || open) {
      // 处理路由监听
      if (!dataRef.current.noState) {
        toggleEvent(open);
      }
    }
    dataRef.current.first = false;
    if (open && !dataRef.current.render) {
      dataRef.current.render = true;
      setInitDom(true);
      setTimeout(() => {
        setInShow(open);
      }, 20);
    } else if (dataRef.current.render) {
      setInShow(open);
      if (destroyOnClose) {
        setTimeout(() => {
          dataRef.current.render = false;
          setInitDom(false);
        }, 250);
      }
    }
  }, [open]);
  
  if (!initDom) return null;
  return ReactDom.createPortal((
    <div className={`popup ${styles['popup']} ${transparent ? styles['transparent'] : ''} ${popupClassName} ${inShow ? styles['popup-show'] : ''} ${round ? styles['pop-round'] : ''}`} style={inStyle}>
      <div className={`popup-mask ${styles['popup-mask']} ${styles[`pop-mask-${position || 'bottom'}`]}`} onClick={onMask} />
      <div className={`popup-inner ${className}  ${styles['popup-inner']} ${styles[`popup-position-${position || 'bottom'}`]}`}>
        {children}
      </div>
    </div>
  ), document.body)
});

export default Popup;