import { useEffect, useRef, useState } from 'react';
import styles from './index.module.less';
import PageBg from '../components/page-bg/page-bg';
import textTglb from '../images/text-tglb.png';
import imgPan from '../images/img-pan.jpg';
import imgPack from '../images/bg-pack.png';
import imgPointer from '../images/img-pan-pointer.png';
import Popup from '../components/popup/popup';

function App(props) {
  // console.log(44, props)
  const dataRef = useRef({
    deg: 0
  });
  const [gifts, setGifts] = useState([
    { value: 1, label: '再接再厉' },
    { value: 2, label: '1.88' },
    { value: 3, label: '2.88' },
    { value: 4, label: '3.88' },
    { value: 5, label: '6.88' },
    { value: 6, label: '8.88' },
    { value: 7, label: '10.88' },
    { value: 8, label: '18.88' },
  ]);
  const [deg, setDeg] = useState(0);
  const [open, setOpen] = useState(false);

  const goLottery = () => {
    const rd = Math.floor(Math.random() * 8);
    dataRef.current.deg = Math.round(dataRef.current.deg / 360) * 360;
    dataRef.current.deg += 1440 + 45 * rd - 20 + 40 * Math.random();
    setDeg(dataRef.current.deg);

    if (rd > 0) {
      setTimeout(() => {
        setOpen(true);
      }, 4300)
    }
  }

  useEffect(() => {
  }, [])

  return (
    <PageBg className={styles['page-lottery']}>
      <img src={textTglb} className={styles['text-tglb']} />
      <div className={styles['pan']}>
        <div className={styles['pan-zhuan']} style={{ transform: `rotate(${deg}deg)`}}>
          {gifts.map((item, index) => <div key={item.value} className={styles['pan-text']} style={{ transform: `rotate(${45 * index}deg)`}}>{item.label}</div>)}
          <img src={imgPan} className={styles['img-pan']} />
        </div>
        <img src={imgPointer} className={styles['img-pointer']} />
        <div className={styles['img-pointer-text']}>立刻<br />抽奖</div>
      </div>
      <div className={styles['text-count']}>您有1次抽奖机会</div>
      <div className={styles['text-tip']}>恭喜通关！精选食安奖品等你拿</div>
      <div className={styles['btn']} onClick={goLottery}>立即开启</div>

      <Popup
        transparent
        closeOnMaskClick
        open={open}
        onClose={() => setOpen(false)}
        className={styles['lottery-pack']}
        position="center"
      >
        <img src={imgPack} className={styles['lp-bg']} />
        <div className={styles['lp-cont']}>
          <div className={styles['lp-money']}>88</div>
          <div className={styles['lp-type']}>现金红包</div>
          <div className={styles['lp-tip']}>点击领取，领取到微信零钱</div>
          <div className={styles['lp-btn']} onClick={() => setOpen(false)}></div>
        </div>
      </Popup>
    </PageBg>
  );
}

export default App;
